var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"BOMI_HB_NULL_NULL","text":{"KOREA":"원♪ 투♬ 원투♬ 짠~","JPN":"ワン♪　 ツー♬　 ワン、ツー♬ 　じゃ～ん。","ENG":"One, ♪ two, ♬ one, two, ♬ tah-dah!","TWN":"一♪二♬一二♬鏘～"},"stage":{"bg":"OFFICE_HEAD","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"BOMI_HB_NULL_NULL","text":{"KOREA":"냐하핫, 오늘은 다른 때보다 움직임이 좋은 거 같네~","JPN":"にゃははっ、今日はいつもよりキレッキレに踊れてる気がするにゃ～。","ENG":"Nya hah hah, looks like I'm really killing it today!","TWN":"喵哈哈，今天的動作好像比以前靈活很多呢喵～"},"stage":{"bg":"OFFICE_HEAD","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"BOMI_HB_NULL_NULL","text":{"KOREA":"그러면 이 기세를 몰아서 시청자들이 깜짝 놀랄 안무를 만들어 볼까낭?","JPN":"ほいじゃ、この勢いでリスナーたちが驚くような振り付けを考えてみようかにゃ～？","ENG":"Alright, then. I'm going to choreograph a dance that'll make my fans freak out!","TWN":"那麼就趁著這個氣勢，編一個能讓觀眾驚豔的舞蹈吧喵？"},"stage":{"bg":"OFFICE_HEAD","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"흠, 보미 양은 다른 일은 몰라도 춤 하나만은 누구보다 열심히 추는군.","JPN":"ふむ、ボミ君は普段の生活はともかく、ダンスに関しては誰よりも一生懸命なのだな。","ENG":"Hmm, I see that you're more committed to dancing than anything else.","TWN":"哦，雖然我對普美小姐的其他事情不太瞭解，但跳舞方面她比其他人都要努力呢。"},"stage":{"bg":"OFFICE_HEAD","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"기왕 파견 나왔으니 현장에서도 분발해 주면 좋겠지만 말이야.","JPN":"せっかく現場に派遣されてきたのだから、仕事にも精を出してくれると嬉しいのだが。","ENG":"Although I'd appreciate the same amount of enthusiasm when you're out on the field.","TWN":"既然都被派遣了，要是她在現場也有這個表現就好了。"},"stage":{"bg":"OFFICE_HEAD","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"BOMI_HB_NULL_NULL","text":{"KOREA":"앗, 사장님? 보고 있었어?","JPN":"あっ、社長？　見てたのにゃ？","ENG":"Oh, Boss? Were you watching me?","TWN":"啊，老闆？您一直都在看嗎？"},"stage":{"bg":"OFFICE_HEAD","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"그럼. 직원들이 잘 지내는지 살피는 것도 사장이 해야 할 일 중 하나 아니겠나.","JPN":"ああ、社員達が元気かどうか確かめるのも社長の務めの一つだ。","ENG":"Of course. A great CEO is always on the lookout for his employees' welfare.","TWN":"當然。視察員工們有沒有好好工作，也是老闆該做的事情之一。"},"stage":{"bg":"OFFICE_HEAD","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L11_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"절대 하릴없이 산책 다니는 건 아닐세!","JPN":"断じて暇つぶしに散歩していたわけではないぞ！","ENG":"I'm not just strolling about because I've got nothing better to do!","TWN":"絕對不是因為沒事幹，所以在閒晃喔！"},"stage":{"bg":"OFFICE_HEAD","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L12_1","type":"dialog","speaker":"BOMI_HB_NULL_NULL","text":{"KOREA":"그렇구나~","JPN":"そうなんだにゃ～。","ENG":"I see.","TWN":"是這樣喔～"},"stage":{"bg":"OFFICE_HEAD","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L13_1","type":"dialog","speaker":"BOMI_HB_NULL_NULL","text":{"KOREA":"구경하고 있으면 구경한다고 말해 주지~ 그럼 더 멋진 안무를 준비해 줬을 텐데냥~","JPN":"見に来るって言ってくれればよかったのに～。\\nそしたらもっと素敵な振り付けを用意して披露してたにゃ～。","ENG":"You could've let me know you'd be watching. I would've prepared something even more awesome!","TWN":"如果你想參觀就直說喵～那我就能準備更棒的舞蹈了喵～"},"stage":{"bg":"OFFICE_HEAD","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L14_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"그래? 방금 본 춤도 보통이 아니라고 생각했는데?","JPN":"そうか？　さっきのダンスも並大抵のものではないと思ったが？","ENG":"Really? The dance I just saw was pretty impressive, too.","TWN":"是嗎？剛剛的舞蹈也很棒啊？"},"stage":{"bg":"OFFICE_HEAD","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L15_1","type":"dialog","speaker":"BOMI_HB_NULL_NULL","text":{"KOREA":"냐하♪ 이 정도야 몸풀기징~♬","JPN":"にゃは♪　こんなのは序の口にゃ～♬","ENG":"Nya hah. ♪ I was just getting warmed up. ♬","TWN":"喵哈♪那只是熱身呀～♬"},"stage":{"bg":"OFFICE_HEAD","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L16_1","type":"dialog","speaker":"BOMI_HB_NULL_NULL","text":{"KOREA":"방금 췄던 춤도 렌즈가 아니라 직접 보면 감흥이 색달랐겠지만~♪","JPN":"さっきのダンスだって、レンズ越しじゃなく生で見たらもっと違ったと思うんだけどにゃ～♪","ENG":"I'm sure you would've enjoyed it more if you saw it yourself, instead of through the robot's cameras. ♪","TWN":"不過剛才的舞如果不是透過鏡頭，而是直接看的話，應該會有完全不同的感受喵～♪"},"stage":{"bg":"OFFICE_HEAD","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L17_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"크흠흠...... 요새 오는 직원들은 다들 눈치가 빠르구만......","JPN":"むむむ……近頃の新入社員はみな察しが良すぎるな……","ENG":"Ahem... I guess all the new employees these days are quite clever...","TWN":"咳咳……最近來的員工觀察力都很好啊……"},"stage":{"bg":"OFFICE_HEAD","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L18_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"그, 그나저나 보미 양은 어쩌다가 춤을 추기 시작했나?","JPN":"そ、それはそうと、ボミ君、ダンスを踊り始めたきかっけは何かね？","ENG":"A-anyway, how did you learn to dance so well?","TWN":"話、話說回來，普米小姐跳舞的契機是什麼？"},"stage":{"bg":"OFFICE_HEAD","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"BOMI_HB_NULL_NULL","text":{"KOREA":"냐하핫♪ 난 복잡하고 우중충한 분위기는 질색이라서냥~♬","JPN":"にゃははっ♪　ボミは難しいお話とか、テンションが下がったりするのは苦手なのにゃ～♬","ENG":"Nya hah hah! ♪ I just don't like it when people are stressed out and gloomy! ♬","TWN":"喵哈哈♪因為我最討厭陰鬱的氣氛了喵～♬"},"stage":{"bg":"OFFICE_HEAD","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"BOMI_HB_NULL_NULL","text":{"KOREA":"그런데 내가 춤을 추면 다들 신나 하잖아. 보미도 춤을 추면 신나니까 일석이조루다가~♬","JPN":"でも、ボミが踊るとみんなが盛り上がるにゃ。踊ってるとボミも楽しくなるから一石二鳥なのにゃ～♬","ENG":"Whenever I dance, everyone gets excited! And I get cheered up myself! One stone, two birds! ♬","TWN":"只要我開始跳舞，大家就會變得很開心；跳起舞來普美也會很開心，也就是一石二鳥喵～♬"},"stage":{"bg":"OFFICE_HEAD","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"그거 참...... 간단하면서도 심오한 이유군 그래.","JPN":"それはまた……シンプルでありながら深い理由だな。","ENG":"That sounds like... a simple but profound reason.","TWN":"那可真是……簡單又深奧的理由呢。"},"stage":{"bg":"OFFICE_HEAD","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"BOMI_HB_NULL_NULL","text":{"KOREA":"맞다, 사장님은 춤 배워 볼 생각 없냥?","JPN":"そうそう、社長はダンスを覚えてみる気はないかにゃ？","ENG":"By the way, have you ever thought about picking up dancing?","TWN":"對了，老闆你不想學學跳舞嗎？"},"stage":{"bg":"OFFICE_HEAD","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"춤? 머신 갑이...... 아니, 내가 말인가?","JPN":"ダンス？　マシーン-甲-が……いや、この私がか？","ENG":"Dancing? Machine G.A.P... Uh, I mean, me?","TWN":"跳舞？妳是說我超帥-Mk……不，妳是說我嗎？"},"stage":{"bg":"OFFICE_HEAD","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L24_1","type":"dialog","speaker":"BOMI_HB_NULL_NULL","text":{"KOREA":"고럼고럼~♪","JPN":"そうにゃ、そうにゃ～♪","ENG":"Yup yup. ♪","TWN":"當然當然呀～♪"},"stage":{"bg":"OFFICE_HEAD","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L25_1","type":"dialog","speaker":"BOMI_HB_NULL_NULL","text":{"KOREA":"음악에 맞춰 몸을 움직이기만 해도 즐거워지니 좋지 않냥?","JPN":"曲に合わせて体を動かすだけでも楽しくなれるからサイコーだにゃ！","ENG":"All you need to do is move your body to the beat. Isn't it great?","TWN":"只需要跟著音樂動起來就能享受樂趣，這不是很好嗎喵？"},"stage":{"bg":"OFFICE_HEAD","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L26_1","type":"dialog","speaker":"BOMI_HB_NULL_NULL","text":{"KOREA":"특히 사장님처럼 일하느라 스트레스 많이 받는 사람에겐 최고야~","JPN":"社長みたいにストレスの多そうな人にはぴったりだにゃ～。","ENG":"It's the perfect thing for someone like you, who gets stressed out from working too much.","TWN":"特別對老闆這種工作壓力大的人來說，是最棒的喵～"},"stage":{"bg":"OFFICE_HEAD","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L27_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"확실히 요새 직원들 챙겨 주느라 스트레스가 많이 쌓이긴 했지.","JPN":"確かに、最近は色々と社員の世話を焼いてるのでストレスが溜まっている。","ENG":"True, I have been stressing out a lot lately because of all the things I have to do for my employees.","TWN":"我最近的確為了照顧員工，累積了很多壓力哪。"},"stage":{"bg":"OFFICE_HEAD","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L28_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"장비 마련해 주랴, 직무 교육 시켜 주랴, 연봉 올려 주랴......","JPN":"装備を用意したり、職務教育を実施したり、さらには年俸も引き上げてやったり……","ENG":"Getting them new gear, providing them training, giving them raises...","TWN":"提供裝備啦，職務教育啦，提高年薪啦等等……"},"stage":{"bg":"OFFICE_HEAD","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"BOMI_HB_NULL_NULL","text":{"KOREA":"거기에 꾸준히 춤을 추면 건강에도 좋다는 사실! 알고 있어?","JPN":"それに、毎日欠かさず踊ると健康にも良いってこと！　知ってたかにゃ？","ENG":"If you dance on a regular basis, it's great for your health, too! Did you know that?","TWN":"而且持續跳舞對身體健康也有好處！你知道嗎？"},"stage":{"bg":"OFFICE_HEAD","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"으음...... 하긴 건강도 자산이지. 언제까지 소홀히 하면 주위에 걱정만 끼칠 거야.","JPN":"うむ……まあ確かに、健康は一番の財産だからな。不摂生で体調を崩せば周りにも迷惑がかかる。","ENG":"Hmm... I suppose staying healthy is an asset. People will get worried about me if I don't take care of myself.","TWN":"嗯……也對，健康也是一種資產啊。如果忽略了這一點，只會讓周圍的人擔心而已。"},"stage":{"bg":"OFFICE_HEAD","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"OLIVIE_COFFIN_NULL_NULL","text":{"KOREA":"그 제안, 잠시만 기다려 주세요.","JPN":"そのお話、少し待ってください。","ENG":"Please hold before you take that offer.","TWN":"那個提案請稍等一下。"},"stage":{"bg":"OFFICE_HEAD","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"BOMI_HB_NULL_NULL","text":{"KOREA":"냐하?","JPN":"にゃはっ？","ENG":"Meow?","TWN":"喵哈？"},"stage":{"bg":"OFFICE_HEAD","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"별일이로군, 올리비에 소장. 지금은 경락 마사지 받고 있을 시간 아닌가?","JPN":"これは珍しいな、オリヴィエ教授。この時間帯は経絡リンパマッサージを受けている頃ではなかったかな？","ENG":"Well, I didn't expect to see you here, Dr. Olivie. Aren't you supposed to be getting a massage right now?","TWN":"太難得了，奧利維亞所長。現在不是妳做經絡按摩的時間嗎？"},"stage":{"bg":"OFFICE_HEAD","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"OLIVIE_COFFIN_NULL_NULL","text":{"KOREA":"연구소에 새로운 실험기기를 들여 놓는 건으로 하나 씨와 얘기 좀 나눴거든요.","JPN":"研究所に新しい実験機器を導入する件で、ナカシマさんと相談をしていました。","ENG":"I had to have a little discussion with Hana over purchasing new lab equipment.","TWN":"因為要在研究所引進新的實驗機器，所以我跟金荷娜小姐談了一會。"},"stage":{"bg":"OFFICE_HEAD","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"OLIVIE_COFFIN_NULL_NULL","text":{"KOREA":"그런데 돌아가는 길에 아주 흥미로운 얘기가 들려서 말이죠.","JPN":"その帰りに、とても興味深い話を耳にしたものですから。","ENG":"Then I overheard something quite interesting on my way back.","TWN":"然後在回來的路上，就聽到了非常有趣的事情呢。"},"stage":{"bg":"OFFICE_HEAD","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"OLIVIE_COFFIN_NULL_NULL","text":{"KOREA":"보미 양에 대해서는 전부터 알고 있었어요. 하트베리에 들어가기 전에도 춤으로 유명했거든요.","JPN":"ボミさんのことは以前から知っていました。ハートベリーに入る前も名の知れたダンサーでしたので。","ENG":"I've known about Bomi long before today. She was quite famous for her dancing even before she joined HRT Berry.","TWN":"普美小姐的事情，我從很久以前就知道了。普美小姐在加入愛心莓果之前就以舞蹈而聞名。"},"stage":{"bg":"OFFICE_HEAD","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"오, 그런가?","JPN":"おお、そうなのか？","ENG":"Oh, is that right?","TWN":"哦，是嗎？"},"stage":{"bg":"OFFICE_HEAD","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"OLIVIE_COFFIN_NULL_NULL","text":{"KOREA":"네. 제 개인적인 연구 결과에 따르면, 보미 양의 춤은 보는 사람에게 긴장감을 해소해 주면서 세로토닌을 분비시키는 효과가 매우 뛰어나답니다.","JPN":"はい。私の個人的な研究結果によりますと、ボミさんの踊りの動作は見る者をリラックスさせると同時に、\\nセロトニン分泌を促進させる効果も極めて優れています。","ENG":"Yes. According to my personal research, Bomi's dance is very effective in helping the viewers relax and inducing their release of serotonin.","TWN":"是的。根據我的個人研究結果顯示，普美小姐的舞蹈能有效消除人們的緊張感，對促進血清素分泌有非常好的效果。"},"stage":{"bg":"OFFICE_HEAD","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"OLIVIE_COFFIN_NULL_NULL","text":{"KOREA":"참고로 세로토닌은 행복을 느끼게 만드는 물질이에요.","JPN":"ちなみにセロトニンは、幸福を感じさせる脳内物質です。","ENG":"By the way, serotonin is the substance that helps you feel happy.","TWN":"順帶一提，血清素是可以讓人感受到幸福的物質。"},"stage":{"bg":"OFFICE_HEAD","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"호오......","JPN":"ほう……","ENG":"Ooh...","TWN":"哦……"},"stage":{"bg":"OFFICE_HEAD","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L47_1","type":"dialog","speaker":"BOMI_HB_NULL_NULL","text":{"KOREA":"처음 알았네♪","JPN":"知らなかったにゃー♪","ENG":"I didn't know that.","TWN":"我第一次聽說♪"},"stage":{"bg":"OFFICE_HEAD","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L49_1","type":"dialog","speaker":"OLIVIE_COFFIN_NULL_NULL","text":{"KOREA":"즉, 보미 양의 춤을 감상하면 스트레스 해소는 물론 면역력과 자연 치유력도 향상시켜 무병장수를 이룰 가능성도 있단 얘기죠.","JPN":"すなわち、ボミさんのダンスを鑑賞すればストレスが解消されるのみならず、\\n免疫力と自然治癒力が向上し、無病長寿を​成し遂げることも夢ではありません。","ENG":"In other words, watching Bomi's dance will not only relieve stress but also improve immunity and healing. Potentially, it could help ensure longevity.","TWN":"換句話說，只要觀賞普美小姐的舞蹈，消解壓力是不在話下、還能提高免疫力和自癒力，實現無病長壽的可能性。"},"stage":{"bg":"OFFICE_HEAD","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"OLIVIE_COFFIN_NULL_NULL","text":{"KOREA":"요즘 비타민만으로는 부족하던 참이었는데, 사장님께서 절 생각해서 이런 인선을 마련해 주실 줄은 몰랐어요.","JPN":"最近はビタミンだけじゃ足りないと感じていたのですけれど、\\n社長が私のためにこんな人選をしてくださるなんて、思いもしませんでしたね。","ENG":"I've been feeling lately that the vitamins aren't doing the trick for me. I appreciate you, Boss, for giving me the opportunity to meet her like this.","TWN":"正好我最近感覺光靠維他命不太夠，沒想到老闆就已經注意到這些，給我安排了這樣的人選。"},"stage":{"bg":"OFFICE_HEAD","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"BOMI_HB_NULL_NULL","text":{"KOREA":"저 언니 눈이 무서워졌다냥......","JPN":"あのお姉ちゃん、目が怖いにゃ……","ENG":"Now her eyes are beaming...","TWN":"那個姐姐的眼神好恐怖喵……"},"stage":{"bg":"OFFICE_HEAD","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L4_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"......들으면 들을수록 사이비 같구만.","JPN":"……それではまるで怪しい健康食品だな。","ENG":"The more I hear, the more ridiculous it sounds.","TWN":"……總覺得越聽越像假的。"},"stage":{"bg":"OFFICE_HEAD","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"OLIVIE_COFFIN_NULL_NULL","text":{"KOREA":"정말 저처럼 재능 있는 미인에게 꼭 필요한 효능이에요.","JPN":"私のように才能ある美人こそが享受すべき効能と言えるでしょう。","ENG":"Seriously, a talented, beautiful woman like me really needs this effect.","TWN":"對於我這樣才華洋溢的美女來說，這是不可或缺的功效啊。"},"stage":{"bg":"OFFICE_HEAD","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"OLIVIE_COFFIN_NULL_NULL","text":{"KOREA":"그러니까 어때요, 보미 양? 한동안 제 연구소에 머물면서 춤을 춰 주는 건?","JPN":"というわけでして、いかがですかボミさん？　しばらく私のラボに滞在して踊ってくれるというのは？","ENG":"So, how about it, Bomi? Why don't you stay at my lab and dance for a while?","TWN":"怎麼樣，普美小姐？要不要暫時待在我的研究所，跳舞給我看呢？"},"stage":{"bg":"OFFICE_HEAD","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"OLIVIE_COFFIN_NULL_NULL","text":{"KOREA":"아, 물론 기한은 길면 길수록 좋아요.","JPN":"そうそう、滞在期間は無期限としましょう。","ENG":"The longer you can stay, the better.","TWN":"啊，期限自然是越長越好。"},"stage":{"bg":"OFFICE_HEAD","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"OLIVIE_COFFIN_NULL_NULL","text":{"KOREA":"물론 지내는 동안 어떤 원리인지 알려면 이런저런 실험도......","JPN":"滞在中に効能の仕組みを解明したいですので、色々な実験も込みで……","ENG":"We could also conduct a few experiments to try and understand the theory behind it...","TWN":"當然，如果想在這段時間知道原理，還需要進行這樣那樣的實驗……"},"stage":{"bg":"OFFICE_HEAD","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"BOMI_HB_NULL_NULL","text":{"KOREA":"도망가자, 사장님! 저 언니 따라가면 영영 못 나올 것 같다냥!","JPN":"ズラかるにゃ、社長！　あのお姉ちゃんについて行ったら一生出られない気がするにゃ！","ENG":"Let's run way, Boss! I don't think she'd ever let me go if I went to her lab!","TWN":"我們逃跑吧，老闆！感覺跟著那個姐姐走的話，我永遠都出不來了喵！"},"stage":{"bg":"OFFICE_HEAD","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BOMI_HB_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L14_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"기, 기다리게!","JPN":"まっ、待ちたまえ！","ENG":"W-wait!","TWN":"等、等等我啊！"},"stage":{"bg":"OFFICE_HEAD","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"OLIVIE_COFFIN_NULL_NULL","text":{"KOREA":"어머나, 말실수를 해 버렸네.","JPN":"あら、つい口がすべっちゃったわ。","ENG":"Oops, maybe I shouldn't have said that last part.","TWN":"哎呀呀，不小心說錯話了啊。"},"stage":{"bg":"OFFICE_HEAD","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LEEYOONJUNG_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L19_1","type":"dialog","speaker":"OLIVIE_COFFIN_NULL_NULL","text":{"KOREA":"뭐, 오늘만 날은 아니죠.","JPN":"まあ、チャンスはいずれまたあるわよね。","ENG":"Well, better luck next time, I guess.","TWN":"算了，反正機會多得是。"},"stage":{"bg":"OFFICE_HEAD","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEYOONJUNG_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L20_1","type":"dialog","speaker":"OLIVIE_COFFIN_NULL_NULL","text":{"KOREA":"다음에 연구소에 오면...... 후후훗.","JPN":"今度研究所に来た日には……フフフ。","ENG":"If she comes to the lab again... Heh heh heh.","TWN":"如果下次她來研究所的話……呵呵呵。"},"stage":{"bg":"OFFICE_HEAD","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEYOONJUNG_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L21_1","type":"dialog","speaker":"LEEYOONJUNG_COFFIN_NULL_NULL","text":{"KOREA":"교수님...... 저희도 슬슬 돌아가야 하지 않을까요......","JPN":"教授……そろそろ帰った方がいいんじゃないっすかね……","ENG":"Professor... Maybe we should start heading back...","TWN":"教授……我們也是時候回去了吧……"},"stage":{"bg":"OFFICE_HEAD","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEYOONJUNG_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"LEEYOONJUNG_COFFIN_NULL_NULL","text":{"KOREA":"한 달만에 밖에 나와서 그런가...... 햇살이 너무...... 따갑네요......","JPN":"さすがに一か月ぶりの外出となると……太陽がしみすぎて……痛いっす……","ENG":"It might be because I haven't been outside for a month... but the sun is... stingingly hot...","TWN":"隔了一個月外出，總感覺……陽光太……刺眼了……"},"stage":{"bg":"OFFICE_HEAD","bgm":"THMEA_HRTBERRY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEYOONJUNG_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};